# Compile a naive convolution kernel with shared memory.
# The kernel deliberately allocates too little shared memory, leading to out‑of‑bounds accesses.
kernel_source = r'''
extern "C" __global__ void conv2d_kernel(const float* __restrict__ input,
                                          const float* __restrict__ weight,
                                          float* __restrict__ output,
                                          int in_channels,
                                          int H_in, int W_in,
                                          int H_out, int W_out,
                                          int kH, int kW,
                                          int stride_h, int stride_w) {
    const int tx = threadIdx.x;
    const int ty = threadIdx.y;
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    int out_x = bx * blockDim.x + tx;
    int out_y = by * blockDim.y + ty;
    if (out_x >= W_out || out_y >= H_out) return;

    // BUG: shared memory is allocated only for blockDim.x * blockDim.y elements,
    // but we index up to (blockDim.x + kW - 1) * (blockDim.y + kH - 1).
    extern __shared__ float s_data[];
    int s_width  = blockDim.x + kW - 1;   // includes halo for kernel width
    int s_height = blockDim.y + kH - 1;   // includes halo for kernel height

    float sum = 0.0f;
    for (int c = 0; c < in_channels; ++c) {
        // Load the required tile (including halo) into shared memory.
        // Each thread loads one element; threads beyond the tile simply skip.
        int load_x = out_x * stride_w - kW/2 + tx;
        int load_y = out_y * stride_h - kH/2 + ty;
        if (tx < s_width && ty < s_height) {
            int idx = c * H_in * W_in + load_y * W_in + load_x;
            // Input is assumed to be padded enough; no bounds check here.
            s_data[ty * s_width + tx] = input[idx];
        }
        __syncthreads();

        // Perform convolution for this output element.
        for (int ky = 0; ky < kH; ++ky) {
            for (int kx = 0; kx < kW; ++kx) {
                float val = s_data[(ty + ky) * s_width + (tx + kx)];
                float w   = weight[c * kH * kW + ky * kW + kx];
                sum += val * w;
            }
        }
        __syncthreads();
    }
    output[out_y * W_out + out_x] = sum;
}
'''

