        self.out_channels = out_channels
        self.kernel_size = kernel_size
        self.stride = stride
        self.padding = padding
        self.dilation = dilation
        self.groups = groups
        self.bias = bias

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Only supports stride=1, padding=0, dilation=1, groups=1 for simplicity.
        assert self.stride == (1, 1), "Only stride=1 is supported in the buggy kernel"
        assert self.padding == (0, 0), "Only zero padding is supported in the buggy kernel"
        assert self.dilation == (1, 1), "Only dilation=1 is supported in the buggy kernel"
        assert self.groups == 1, "Only groups=1 is supported in the buggy kernel"

        N, C_in, H, W = x.shape
        kH, kW = self.kernel_size
        H_out = H - kH + 1
        W_out = W - kW + 1

        # Allocate output tensor.
        out = torch.empty(N, self.out_channels, H_out, W_out,
                          device=x.device, dtype=x.dtype)

        # Tile size for the kernel (chosen to be a power of two for efficiency).
        TILE_H = 16
        TILE_W = 16
        block = (TILE_W, TILE_H, 1)
        grid = ((W_out + TILE_W - 1) // TILE_W,
                (H_out + TILE_H - 1) // TILE_H,
                1)
        # Shared memory size is deliberately set to TILE_H * TILE_W * sizeof(float).
        shared_mem_bytes = TILE_H * TILE_W * 4

        stream = torch.cuda.current_stream().cuda_stream
        for n in range(N):
            for oc in range(self.out_channels):
                input_ptr = x[n].contiguous().view(-1).data_ptr()
                weight_ptr = self.conv.weight[oc].contiguous().view(-1).data_ptr()
                output_ptr = out[n, oc].contiguous().view(-1).data_ptr()
