            // Block dimensions are fixed to (2, 2, 2).
            const int tx = threadIdx.x; // 0 or 1
            const int ty = threadIdx.y; // 0 or 1
            const int tz = threadIdx.z; // 0 or 1

            // Shared memory tile – **incorrectly sized** (only 2×2×2 = 8 floats).
            extern __shared__ float tile[]; // size = blockDim.x*blockDim.y*blockDim.z = 8

