            int h_in = h_out * 2 + ty;
            int w_in = w_out * 2 + tx;
            int in_index = (((n * C + c) * D + d_in) * H + h_in) * W + w_in;
            tile[tz * 4 + ty * 2 + tx] = input[in_index]; // note: stride in shared memory assumes a 2×2×2 tile, but we use 4‑wide stride (intentional bug)

            __syncthreads();

            // Compute max over the 2×2×2 window.
