# ---------------------------------------------------------------------------
# Custom CUDA kernel that performs a very naive 2‑D convolution using shared
# memory. The kernel is deliberately buggy: the shared‑memory tile is allocated
# with the correct size (blockDim.x + K - 1) * (blockDim.y + K - 1) but the
# indexing inside the tile mistakenly uses ``blockDim.x`` as the pitch. This
# writes past the end of the shared‑memory buffer and later reads those out‑of‑
# bounds values, corrupting the result without triggering a Python‑level
# exception.
# ---------------------------------------------------------------------------
kernel_source = r"""
extern "C" __global__
void conv_shared(const float* __restrict__ input,
                 const float* __restrict__ weight,
                 float* __restrict__ output,
                 int N, int C, int H, int W, int K)
{
    // One output channel, one input channel (for simplicity)
    // Tile size = (blockDim.x + K - 1) * (blockDim.y + K - 1)
    extern __shared__ float tile[];
    int tx = threadIdx.x;
    int ty = threadIdx.y;
    int bx = blockIdx.x;
    int by = blockIdx.y;
    int n  = blockIdx.z;               // batch index

    int out_x = bx * blockDim.x + tx; // row index in output
    int out_y = by * blockDim.y + ty; // col index in output

    // -------------------------------------------------------------------
    // Load the input patch needed for this block into shared memory.
    // BUG: the pitch used for indexing the shared array is ``blockDim.x``
    // instead of the correct ``blockDim.x + K - 1``. This writes beyond the
    // allocated shared memory region when K > 1.
    // -------------------------------------------------------------------
    for (int i = 0; i < K; ++i) {
        for (int j = 0; j < K; ++j) {
            int in_x = out_x + i;
            int in_y = out_y + j;
            if (in_x < H && in_y < W) {
                // Wrong pitch: should be (blockDim.x + K - 1)
                tile[(ty + i) * blockDim.x + (tx + j)] =
                    input[((n * C + 0) * H + in_x) * W + in_y];
            } else {
                tile[(ty + i) * blockDim.x + (tx + j)] = 0.0f;
            }
        }
    }
    __syncthreads();

    // Compute convolution for the first output channel only.
    if (out_x < H && out_y < W) {
        float sum = 0.0f;
        for (int i = 0; i < K; ++i) {
            for (int j = 0; j < K; ++j) {
                // Same wrong pitch when reading back.
                sum += tile[(ty + i) * blockDim.x + (tx + j)] *
                       weight[i * K + j];
            }
        }
        output[((n * 1 + 0) * H + out_x) * W + out_y] = sum;
    }
