    """A thin wrapper around the buggy CUDA kernel.

    The wrapper only supports a single input and output channel and a square
    kernel. It mimics ``nn.Conv2d`` with stride=1 and no padding.
    """
    assert input_tensor.is_cuda and weight_tensor.is_cuda, "Tensors must be on CUDA"
    N, C_in, H, W = input_tensor.shape
    C_out, C_weight, K, K2 = weight_tensor.shape
    assert C_in == 1 and C_out == 1 and C_weight == 1 and K == K2, "Only 1‑in/1‑out channel supported"

