    shared_mem_bytes = (block[0] + K - 1) * (block[1] + K - 1) * 4
    conv_mod.conv_shared(grid=grid,
                         block=block,
                         args=[input_tensor.contiguous(),
                               weight_tensor.contiguous(),
                               output,
                               N, C_in, H, W, K],
                         stream=torch.cuda.current_stream().cuda_stream,
                         shared_mem=shared_mem_bytes)
    return output


