cuda_src = r"""
extern "C" __global__
void matmul_shared(const float* A, const float* B, float* C,
                   int M, int N, int K) {
    const int TILE = 32;  // Expected tile size
    extern __shared__ float sh[];  // Shared memory buffer (insufficiently sized)
    float* As = sh;                     // TILE * TILE floats
    float* Bs = sh + TILE * TILE;       // TILE * TILE floats
    int row = blockIdx.y * TILE + threadIdx.y;
    int col = blockIdx.x * TILE + threadIdx.x;
    float value = 0.0f;
    int numTiles = (K + TILE - 1) / TILE;
    for (int t = 0; t < numTiles; ++t) {
        // Load A tile
        int aRow = row;
        int aCol = t * TILE + threadIdx.x;
        if (aRow < M && aCol < K)
            As[threadIdx.y * TILE + threadIdx.x] = A[aRow * K + aCol];
        else
            As[threadIdx.y * TILE + threadIdx.x] = 0.0f;
        // Load B tile
        int bRow = t * TILE + threadIdx.y;
        int bCol = col;
        if (bRow < K && bCol < N)
            Bs[threadIdx.y * TILE + threadIdx.x] = B[bRow * N + bCol];
        else
            Bs[threadIdx.y * TILE + threadIdx.x] = 0.0f;
        __syncthreads();
        // Compute partial product
        for (int i = 0; i < TILE; ++i) {
            value += As[threadIdx.y * TILE + i] * Bs[i * TILE + threadIdx.x];
        }
        __syncthreads();
    }
    if (row < M && col < N) {
        C[row * N + col] = value;
    }
