def _matmul_shared(a: torch.Tensor, b: torch.Tensor) -> torch.Tensor:
    """Matrix multiplication using the buggy shared‑memory kernel.
    a: (M, K), b: (K, N) on CUDA.
    """
    if not a.is_cuda or not b.is_cuda:
        raise RuntimeError('Both inputs must be CUDA tensors')
    M, K = a.shape
    K2, N = b.shape
    assert K == K2, 'Incompatible shapes for matmul'
    c = torch.empty(M, N, device=a.device, dtype=a.dtype)
    TILE = 32
    grid = ((N + TILE - 1) // TILE, (M + TILE - 1) // TILE)
    block = (TILE, TILE, 1)
    # Intentionally allocate shared memory for a 16x16 tile (insufficient for TILE=32)
    shared_mem_bytes = 2 * 16 * 16 * 4  # two buffers (A and B), float32 = 4 bytes
    _matmul_mod.matmul_shared(grid=grid,
                              block=block,
                              args=[a.contiguous(), b.contiguous(), c, M, N, K],
                              stream=torch.cuda.current_stream(),
                              shared_mem=shared_mem_bytes)
