        extern "C" __global__
        void mse_kernel(const float* pred, const float* targ, float* out, int N) {
            extern __shared__ float sdata[];               // shared memory buffer
            int idx = blockIdx.x * blockDim.x + threadIdx.x;
            float diff = 0.0f;
            if (idx < N) {
                diff = pred[idx] - targ[idx];
                sdata[threadIdx.x] = diff * diff;          // store per‑thread contribution
            } else {
                sdata[threadIdx.x] = 0.0f;
            }
            __syncthreads();

            // Parallel reduction (assumes shared memory of size blockDim.x)
            for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
                if (threadIdx.x < stride) {
                    sdata[threadIdx.x] += sdata[threadIdx.x + stride];
                }
                __syncthreads();
            }

            if (threadIdx.x == 0) {
                atomicAdd(out, sdata[0]);
            }
        }
