        # Ensure inputs are on CUDA and have the same shape.
        if not predictions.is_cuda or not targets.is_cuda:
            raise RuntimeError('ModelNew expects CUDA tensors')
        if predictions.shape != targets.shape:
            raise ValueError('Shape mismatch between predictions and targets')

        N = predictions.numel()
        # Output accumulator (single float) on the same device.
        out = torch.zeros(1, device=predictions.device, dtype=predictions.dtype)

        # Convert tensors to CuPy arrays to obtain raw device pointers.
        pred_cp = cp.asarray(predictions)
        targ_cp = cp.asarray(targets)
        out_cp = cp.asarray(out)

        # Kernel launch configuration.
        block = 256
        grid = (N + block - 1) // block
        # *** BUG ***: shared memory size is mistakenly set to half the required amount.
        # Correct size would be block * sizeof(float). Using block//2 leads to out‑of‑bounds
        # accesses inside the kernel's reduction loop.
        shared_mem_bytes = (block // 2) * 4  # 4 bytes per float, but should be block * 4.

