        self._kernel((grid,), (block,), (pred_cp.data.ptr,
                                         targ_cp.data.ptr,
                                         out_cp.data.ptr,
                                         N),
                     shared_mem=shared_mem_bytes)
        # Synchronize to ensure kernel completion before reading the result.
        cp.cuda.Stream.null.synchronize()

        # Convert the accumulator back to a PyTorch scalar and compute the mean.
        total_sq_error = out.item()
