_kernel_code = r"""
extern "C" __global__
void att_kernel(const float* __restrict__ q,
                const float* __restrict__ k,
                float* __restrict__ att,
                const int T,
                const int hs,
                const float scale) {
    // Shared memory sized for a fixed tile (TILE = 32).  The launch config always
    // uses 32 threads, even when T > 32.  This means only the first 32 rows are
    // loaded into shared memory, but the kernel later indexes up to (T-1).
    extern __shared__ float sh[]; // size = TILE * hs floats (TILE = 32)
    int tid = threadIdx.x;
    int bid = blockIdx.x; // batch * head index

    // Load a row of Q into shared memory (only when tid < T).
    if (tid < T) {
        for (int d = 0; d < hs; ++d) {
            sh[tid * hs + d] = q[bid * T * hs + tid * hs + d];
        }
    }
    __syncthreads();

    // Compute attention for each query position (tid) against all keys (j).
    if (tid < T) {
        for (int j = 0; j < T; ++j) {
            float dot = 0.0f;
            for (int d = 0; d < hs; ++d) {
                // Off‑by‑one error: (j + 1) can equal T, which is beyond the
                // allocated shared memory (max index is (TILE-1) * hs + d).
                dot += sh[(j + 1) * hs + d] * k[bid * T * hs + j * hs + d];
            }
            att[bid * T * T + tid * T + j] = dot * scale;
        }
    }
}
"""

# Compile the kernel once.
_att_kernel = cp.RawKernel(_kernel_code, 'att_kernel')


class ModelNew(nn.Module):
    """
    A multi‑head masked self‑attention layer with a projection at the end that uses
    ReLU instead of Softmax.  The attention matrix is computed via a custom CUDA
    kernel that contains a shared‑memory size bug.
    """

    def __init__(self, n_embd, n_head, max_seqlen):
        super().__init__()
        assert n_embd % n_head == 0
        self.c_attn = nn.Linear(n_embd, 3 * n_embd)
        self.c_proj = nn.Linear(n_embd, n_embd)
        self.register_buffer(
            "bias",
            torch.tril(torch.ones(max_seqlen, max_seqlen))
            .view(1, 1, max_seqlen, max_seqlen)
        )
        self.n_head = n_head
        self.n_embd = n_embd

    def forward(self, x):
        B, T, C = x.size()
        # Linear projection and split
        q, k, v = self.c_attn(x).split(self.n_embd, dim=2)
        # Reshape for multi‑head
        k = k.view(B, T, self.n_head, C // self.n_head).transpose(1, 2)  # (B, nh, T, hs)
        q = q.view(B, T, self.n_head, C // self.n_head).transpose(1, 2)  # (B, nh, T, hs)
        v = v.view(B, T, self.n_head, C // self.n_head).transpose(1, 2)  # (B, nh, T, hs)

        # -------------------------------------------------------------------
        # Compute attention scores using the buggy CUDA kernel.
        # -------------------------------------------------------------------
        hs = C // self.n_head  # head size
        scale = 1.0 / math.sqrt(hs)
        # Flatten batch and heads for the kernel launch.
        q_flat = q.contiguous().view(B * self.n_head, T, hs)
        k_flat = k.contiguous().view(B * self.n_head, T, hs)
        # Convert to CuPy arrays (copies data to GPU memory accessible by CuPy).
        q_cu = cp.asarray(q_flat)
        k_cu = cp.asarray(k_flat)
        att_cu = cp.empty((B * self.n_head, T, T), dtype=cp.float32)
        # Fixed tile size – this is the source of the memory‑access violation.
        TILE = 32
        shared_mem_bytes = TILE * hs * 4  # 4 bytes per float
        # Launch configuration: one block per (batch * head).
        _att_kernel(
            (B * self.n_head,),  # grid
            (TILE,),             # block
            (q_cu, k_cu, att_cu, int(T), int(hs), float(scale)),
            shared_mem=shared_mem_bytes,
        )
        # Bring the result back into a torch tensor on the same device.
        att = torch.utils.dlpack.from_dlpack(att_cu.toDlpack())
        att = att.view(B, self.n_head, T, T)

        # Apply causal mask and ReLU (instead of softmax).
        att = att.masked_fill(self.bias[:, :, :T, :T] == 0, float('-inf'))
        att = F.relu(att)

        # Attend to values.
        y = att @ v  # (B, nh, T, T) x (B, nh, T, hs) -> (B, nh, T, hs)
        y = y.transpose(1, 2).contiguous().view(B, T, C)
        y = self.c_proj(y)
        return y


