kernel_source = r'''
extern "C" __global__
void tiled_gemm(const float* __restrict__ A,
                const float* __restrict__ B,
                float* __restrict__ C,
                const int M,
                const int N,
                const int K) {
    const int TILE_SIZE = 16; // tile dimension (both rows and cols)
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;
    float acc = 0.0f;

    // Loop over tiles of K dimension
    for (int t = 0; t < (K + TILE_SIZE - 1) / TILE_SIZE; ++t) {
        // Load A tile
        int aRow = row;
        int aCol = t * TILE_SIZE + threadIdx.x;
        // OFF‑BY‑ONE: should be < K, but we use <= which can read one element past the end
        As[threadIdx.y][threadIdx.x] = (aRow < M && aCol <= K) ? A[aRow * K + aCol] : 0.0f;
        // Load B tile
        int bRow = t * TILE_SIZE + threadIdx.y;
        int bCol = col;
        Bs[threadIdx.y][threadIdx.x] = (bRow <= K && bCol < N) ? B[bRow * N + bCol] : 0.0f;
        __syncthreads();

        // Compute partial product
        for (int i = 0; i < TILE_SIZE; ++i) {
            acc += As[threadIdx.y][i] * Bs[i][threadIdx.x];
        }
        __syncthreads();
    }
    if (row < M && col < N) {
        C[row * N + col] = acc;
    }
}
